  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, any>) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Record<string, any>[]>;
}

interface Cell {
  raw: string;
  quoted: boolean;
}

class CSVResultImpl implements CSVResult {
  constructor(
    public rows: Record<string, any>[],
    public headers: string[],
    public errors: CSVError[]
  ) {}

  filter(predicate: (row: Record<string, any>) => boolean): CSVResult {
    const filteredRows = this.rows.filter(predicate);
    return new CSVResultImpl(filteredRows, this.headers, this.errors);
  }

  sum(column: string): number {
    return this.rows.reduce((acc, row) => {
      const value = row[column];
      if (typeof value === 'number' && !Number.isNaN(value)) {
        return acc + value;
      }
      return acc;
    }, 0);
  }

  average(column: string): number {
    let total = 0;
    let count = 0;
    for (const row of this.rows) {
      const value = row[column];
      if (typeof value === 'number' && !Number.isNaN(value)) {
        total += value;
        count++;
      }
    }
    return count === 0 ? 0 : total / count;
  }

  count(): number {
    return this.rows.length;
  }

  groupBy(column: string): Map<any, Record<string, any>[]> {
    const map = new Map<any, Record<string, any>[]>();
    for (const row of this.rows) {
      const key = row[column];
      const existing = map.get(key);
      if (existing) {
        existing.push(row);
      } else {
        map.set(key, [row]);
      }
    }
    return map;
  }
}

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const data = input ?? '';
  const delimiterText =
    options?.delimiter && options.delimiter.length > 0 ? options.delimiter : ',';
  const delimiterLength = delimiterText.length;
  const quoteText =
    options?.quote && options.quote.length > 0 ? options.quote : '"';
  const quoteChar = quoteText[0];
  const lineSeparatorOption =
    options?.lineSeparator && options.lineSeparator.length > 0
      ? options.lineSeparator
      : undefined;

  const rows: Cell[][] = [];
  const rowLineNumbers: number[] = [];
  const errors: CSVError[] = [];

  let currentRow: Cell[] = [];
  let currentField = '';
  let currentFieldQuoted = false;
  let fieldStarted = false;
  let inQuotes = false;
  let currentLineNumber = 1;
  let justHitDelimiter = false;

  const finalizeField = () => {
    currentRow.push({ raw: currentField, quoted: currentFieldQuoted });
    currentField = '';
    currentFieldQuoted = false;
    fieldStarted = false;
  };

  const flushFieldIfNecessary = (allowEmptyFallback: boolean) => {
    if (fieldStarted || currentField !== '' || currentFieldQuoted) {
      finalizeField();
      justHitDelimiter = false;
      return true;
    }
    if (justHitDelimiter) {
      finalizeField();
      justHitDelimiter = false;
      return true;
    }
    if (allowEmptyFallback && currentRow.length === 0) {
      finalizeField();
      justHitDelimiter = false;
      return true;
    }
    return false;
  };

  const pushRow = (allowEmptyFallback: boolean) => {
    flushFieldIfNecessary(allowEmptyFallback);
    rows.push(currentRow);
    rowLineNumbers.push(currentLineNumber);
    currentRow = [];
    justHitDelimiter = false;
  };

  const detectLineSeparatorLength = (index: number): number => {
    if (lineSeparatorOption) {
      if (data.startsWith(lineSeparatorOption, index)) {
        return lineSeparatorOption.length;
      }
      return 0;
    }
    const char = data[index];
    if (char === '\r') {
      if (data[index + 1] === '\n') {
        return 2;
      }
      return 1;
    }
    if (char === '\n') {
      return 1;
    }
    return 0;
  };

  const isDelimiterAt = (index: number): boolean => {
    if (delimiterLength === 0) {
      return false;
    }
    return data.startsWith(delimiterText, index);
  };

  for (let i = 0; i < data.length; i++) {
    const char = data[i];
    if (inQuotes) {
      if (char === quoteChar) {
        const nextChar = data[i + 1];
        if (nextChar === quoteChar) {
          currentField += quoteChar;
          i++;
        } else {
          inQuotes = false;
        }
        fieldStarted = true;
        continue;
      }
      currentField += char;
      continue;
    }

    const delimiterMatch = isDelimiterAt(i);
    if (delimiterMatch) {
      flushFieldIfNecessary(true);
      justHitDelimiter = true;
      i += delimiterLength - 1;
      continue;
    }

    const lineSeparatorLength = detectLineSeparatorLength(i);
    if (lineSeparatorLength > 0) {
      pushRow(true);
      currentLineNumber++;
      i += lineSeparatorLength - 1;
      continue;
    }

    if (!fieldStarted && char === quoteChar) {
      inQuotes = true;
      currentFieldQuoted = true;
      fieldStarted = true;
      justHitDelimiter = false;
      continue;
    }

    currentField += char;
    fieldStarted = true;
    justHitDelimiter = false;
  }

  const pushFinalRowIfNeeded = () => {
    const hasPendingField =
      fieldStarted || currentField !== '' || currentFieldQuoted || justHitDelimiter;
    const hasPreviousCells = currentRow.length > 0;
    if (hasPreviousCells || hasPendingField) {
      flushFieldIfNecessary(false);
      rows.push(currentRow);
      rowLineNumbers.push(currentLineNumber);
      currentRow = [];
      justHitDelimiter = false;
    }
  };

  pushFinalRowIfNeeded();

  if (inQuotes) {
    const unterminatedRowNumber =
      rowLineNumbers.length > 0
        ? rowLineNumbers[rowLineNumbers.length - 1]
        : currentLineNumber;
    errors.push({
      row: unterminatedRowNumber,
      message: 'Unterminated quoted field detected',
    });
  }

  if (rows.length === 0) {
    return new CSVResultImpl([], [], errors);
  }

  const headerCells = rows[0];
  const headers = headerCells.map((cell) => cell.raw.trim());
  const dataRows: Record<string, any>[] = [];

  const coerceValue = (cell: Cell): any => {
    const rawValue = cell.quoted ? cell.raw : cell.raw.trim();
    const normalizedValue = rawValue;
    if (normalizedValue === '' || normalizedValue.toLowerCase() === 'null') {
      return null;
    }
    const lower = normalizedValue.toLowerCase();
    if (lower === 'true') {
      return true;
    }
    if (lower === 'false') {
      return false;
    }
    const numericPattern = /^[-+]?(?:\d+(?:\.\d*)?|\.\d+)$/;
    if (numericPattern.test(normalizedValue)) {
      const numericValue = Number(normalizedValue);
      if (!Number.isNaN(numericValue)) {
        return numericValue;
      }
    }
    return normalizedValue;
  };

  for (let rowIndex = 1; rowIndex < rows.length; rowIndex++) {
    const rowCells = rows[rowIndex];
    const rowNumber = rowLineNumbers[rowIndex];
    if (rowCells.length !== headers.length) {
      errors.push({
        row: rowNumber,
        message: `Row ${rowNumber} has ${rowCells.length} column(s) but expected ${headers.length}`,
      });
    }
    const normalizedCells = rowCells.slice(0, headers.length);
    while (normalizedCells.length < headers.length) {
      normalizedCells.push({ raw: '', quoted: false });
    }
    const rowObject: Record<string, any> = {};
    for (let columnIndex = 0; columnIndex < headers.length; columnIndex++) {
      const headerName = headers[columnIndex];
      const cell = normalizedCells[columnIndex];
      rowObject[headerName] = cell ? coerceValue(cell) : null;
    }
    dataRows.push(rowObject);
  }

  return new CSVResultImpl(dataRows, headers, errors);
}

import { parseCSV } from './csv-parser';

function assert(condition: boolean, message?: string) {
  if (!condition) {
    throw new Error(message ?? 'Assertion failed');
  }
}

function assertEqual(actual: any, expected: any, message?: string) {
  if (actual !== expected) {
    throw new Error(
      message ?? `Expected ${JSON.stringify(expected)}, but received ${JSON.stringify(actual)}`
    );
  }
}

function assertDeepEqual(actual: any, expected: any, message?: string) {
  const actualJson = JSON.stringify(actual);
  const expectedJson = JSON.stringify(expected);
  if (actualJson !== expectedJson) {
    throw new Error(
      message ?? `Expected ${expectedJson}, but received ${actualJson}`
    );
  }
}

function testBasicParsing() {
  const result = parseCSV('name,age\nAlice,30\nBob,25');
  assertEqual(result.headers.length, 2, 'Header count mismatch');
  assertEqual(result.rows.length, 2, 'Row count mismatch');
  assertEqual(result.rows[0].name, 'Alice');
  assertEqual(result.rows[0].age, 30);
  assertEqual(result.rows[1].name, 'Bob');
  assertEqual(result.rows[1].age, 25);
  assertEqual(result.errors.length, 0);
}

function testQuotedFieldsAndCommas() {
  const result = parseCSV('id,note\n1,"hello, world"\n2,"value, has comma"');
  assertEqual(result.rows[0].note, 'hello, world');
  assertEqual(result.rows[1].note, 'value, has comma');
}

function testEscapedQuotes() {
  const result = parseCSV('quote\n"She said ""Hi"""');
  assertEqual(result.rows[0].quote, 'She said "Hi"');
}

function testCustomDelimiterAndLineSeparator() {
  const input = 'key;value||A;1||B;2';
  const result = parseCSV(input, { delimiter: ';', lineSeparator: '||' });
  assertEqual(result.headers[0], 'key');
  assertEqual(result.headers[1], 'value');
  assertEqual(result.rows.length, 2);
  assertEqual(result.rows[0].value, 1);
  assertEqual(result.rows[1].value, 2);
}

function testTypeCoercion() {
  const csv =
    'num,int_float,bool_true,bool_false,nullish,empty,str\n' +
    '42,-3.14,true,FALSE,NULL,,hello';
  const result = parseCSV(csv);
  const row = result.rows[0];
  assertEqual(row.num, 42);
  assertEqual(typeof row.num, 'number');
  assertEqual(row.int_float, -3.14);
  assertEqual(typeof row.int_float, 'number');
  assertEqual(row.bool_true, true);
  assertEqual(row.bool_false, false);
  assertEqual(row.nullish, null);
  assertEqual(row.empty, null);
  assertEqual(row.str, 'hello');
}

function testMalformedRows() {
  const csv = 'id,name\n1,A,extra\n2';
  const result = parseCSV(csv);
  assertEqual(result.rows.length, 2);
  assertEqual(result.errors.length, 2);
  assert(
    result.errors.some((error) => error.row === 2 && error.message.includes('expected')),
    'Missing error for row 2'
  );
  assert(
    result.errors.some((error) => error.row === 3 && error.message.includes('expected')),
    'Missing error for row 3'
  );
  assertEqual(result.rows[1].name, null);
}

function testFilteringAndAggregationOnFilter() {
  const csv = 'id,value\n1,5\n2,15\n3,20';
  const result = parseCSV(csv);
  const filtered = result.filter((row) => row.value >= 15);
  assertEqual(filtered.rows.length, 2);
  assertEqual(filtered.rows[0].id, 2);
  assertEqual(filtered.rows[1].id, 3);
  assertEqual(filtered.sum('value'), 35);
  assertEqual(filtered.count(), 2);
}

function testAggregationMethods() {
  const csv = 'category,value\nA,10\nB,20\nA,30\nC,5';
  const result = parseCSV(csv);
  assertEqual(result.sum('value'), 65);
  assertEqual(result.average('value'), 16.25);
  assertEqual(result.count(), 4);
  const grouped = result.groupBy('category');
  assert(grouped.has('A'));
  assert(grouped.has('B'));
  assert(grouped.has('C'));
  assertEqual(grouped.get('A')?.length, 2);
  assertEqual(grouped.get('B')?.[0].value, 20);
  assertEqual(grouped.get('C')?.[0].value, 5);
}

function testEdgeCases() {
  const empty = parseCSV('');
  assertEqual(empty.rows.length, 0);
  assertEqual(empty.headers.length, 0);
  assertEqual(empty.errors.length, 0);
  assertEqual(empty.count(), 0);
  assertEqual(empty.sum('anything'), 0);
  assertEqual(empty.average('anything'), 0);

  const singleColumn = parseCSV('only\nvalue');
  assertEqual(singleColumn.rows.length, 1);
  assertEqual(singleColumn.rows[0].only, 'value');

  const singleRow = parseCSV('flag\ntrue');
  assertEqual(singleRow.rows.length, 1);
  assertEqual(singleRow.rows[0].flag, true);

  const largeText = 'x'.repeat(10000);
  const bigCsv = `label,notes\n1,"${largeText}"`;
  const bigResult = parseCSV(bigCsv);
  assertEqual(bigResult.rows[0].notes.length, 10000);
  assertEqual(bigResult.rows[0].notes, largeText);
}

function runTests() {
  testBasicParsing();
  testQuotedFieldsAndCommas();
  testEscapedQuotes();
  testCustomDelimiterAndLineSeparator();
  testTypeCoercion();
  testMalformedRows();
  testFilteringAndAggregationOnFilter();
  testAggregationMethods();
  testEdgeCases();
  console.log('All csv-parser tests passed.');
}

runTests();

